#include <bits/stdc++.h>
using namespace std;
int n;
const int maxn = 10;
int a[maxn][maxn];
int dp[maxn][maxn][maxn][maxn];
int main(){
	cin>>n;
	int x,y,num;
	while(cin>>x>>y>>num){
		if(x==0)
			break;
		a[x][y]=num;
	}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			for(int k=1;k<=n;k++)
				for(int l=1;l<=n;l++){
					dp[i][j][k][l]=max(max(dp[i - 1][j][k - 1][l],
					dp[i-1][j][k][l-1]),
					max(dp[i][j-1][k-1][l],
					dp[i][j-1][k][l-1]));
					dp[i][j][k][l]+=a[i][j];
					if (i!=k&&j!=l)
						dp[i][j][k][l]+=a[k][l];
				}
	cout<<dp[n][n][n][n];
	return 0;
}
